+import { useCallback, useState } from "react";
+import type { NexusSFConfig } from "@nexus-sf/types";
+import {
+  NexusSFProvider,
+  useNexusSF,
+  useTranscript,
+  useNetworkStats,
+} from "./hooks/nexus-hooks";
+import { ConferenceView } from "./ui/components/ConferenceView";
+import { ParticipantGrid } from "./ui/components/ParticipantGrid";
+import { ControlBar } from "./ui/components/ControlBar";
+import { TranscriptPanel } from "./ui/components/TranscriptPanel";
+import { TranscriptOverlay } from "./ui/components/TranscriptOverlay";
+import { ConnectionHealth } from "./ui/components/ConnectionHealth";
+
+const DEFAULT_CONFIG: NexusSFConfig = {
+  serverUrl: "https://localhost:4433",
+  transcription: { enabled: true, mode: "server-first", language: "en", phraseHints: [] },
+  quality: { target: "balanced", maxBitrate: 48000 },
+  translation: { enabled: false, targetLanguages: [] },
+  meetingIntelligence: { summaries: true, actionItems: true, entities: true },
+  ai: { participants: [] },
+  security: { mode: "server-readable", retention: "stored" },
+};
+
+function Conference() {
+  const { isConnected, session, controls, participants, error } =
+    useNexusSF(DEFAULT_CONFIG);
+  const transcript = useTranscript(session);
+  const stats = useNetworkStats(session);
+
+  // Map hook transcript entries to TranscriptPanel's richer type
+  const panelEntries = transcript.map((e) => ({
+    id: e.id,
+    speaker: e.speaker,
+    speakerId: e.speaker,
+    text: e.text,
+    isInterim: e.isInterim,
+    timestamp: e.timestamp,
+    hasCorrection: false,
+    revisionCount: 0,
+  }));
+
+  return (
+    <ConferenceView
+      isConnected={isConnected}
+      error={error}
+      mainContent={<ParticipantGrid participants={participants} />}
+      sidePanel={<TranscriptPanel entries={panelEntries} />}
+      controlBar={
+        <ControlBar
+          isMuted={controls.isMuted}
+          isConnected={isConnected}
+          onToggleMute={controls.toggleMute}
+          onLeave={controls.leave}
+        />
+      }
+      connectionHealth={
+        <ConnectionHealth
+          rtt={stats.rtt}
+          loss={stats.loss}
+          estimatedBandwidth={stats.estimatedBandwidth}
+          degradationTier={stats.degradationTier}
+          connectionState={stats.connectionState}
+        />
+      }
+      transcriptOverlay={<TranscriptOverlay entries={transcript} />}
+    />
+  );
+}
+
+function PreJoinScreen({ onJoin }: { onJoin: (room: string, name: string) => void }) {
+  const [roomId, setRoomId] = useState("");
+  const [displayName, setDisplayName] = useState("");
+
+  const handleSubmit = useCallback(
+    (e: React.FormEvent) => {
+      e.preventDefault();
+      if (roomId.trim() && displayName.trim()) {
+        onJoin(roomId.trim(), displayName.trim());
+      }
+    },
+    [roomId, displayName, onJoin],
+  );
+
+  return (
+    <div className="nexus-prejoin-screen">
+      <h1>NEXUS-SF</h1>
+      <p>Semantic Frame Conferencing</p>
+      <form onSubmit={handleSubmit} className="nexus-prejoin-form">
+        <label>
+          Room ID
+          <input
+            type="text"
+            value={roomId}
+            onChange={(e) => setRoomId(e.target.value)}
+            placeholder="e.g. daily-standup"
+            autoFocus
+          />
+        </label>
+        <label>
+          Display Name
+          <input
+            type="text"
+            value={displayName}
+            onChange={(e) => setDisplayName(e.target.value)}
+            placeholder="e.g. Alice"
+          />
+        </label>
+        <button type="submit" disabled={!roomId.trim() || !displayName.trim()}>
+          Join Room
+        </button>
+      </form>
+    </div>
+  );
+}
+
+export function App() {
+  const [joined, setJoined] = useState<{ roomId: string; displayName: string } | null>(null);
+
+  if (!joined) {
+    return (
+      <PreJoinScreen
+        onJoin={(roomId, displayName) => setJoined({ roomId, displayName })}
+      />
+    );
+  }
+
+  return (
+    <NexusSFProvider config={DEFAULT_CONFIG}>
+      <Conference />
+    </NexusSFProvider>
+  );
+}
